import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import "./Login.css";

const Login = () => {
  const [formData, setFormData] = useState({ libraryId: "", email: "", password: "" });
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const { libraryId, email, password } = formData;

    if (!libraryId || !email || !password) {
      toast.error("All fields are required.", { position: "top-center", autoClose: 3000 });
      return;
    }
    
    toast.success("Login Successful ✅", { position: "top-center", autoClose: 3000 });
    setTimeout(() => navigate("/library"), 2000);
  };

  return (
    <div className="auth-container">
      <div className="auth-box">
        <h2>📚 Library Portal</h2>
        <form onSubmit={handleSubmit}>
          <input type="text" name="libraryId" placeholder="Library ID" value={formData.libraryId} onChange={handleChange} required />
          <input type="email" name="email" placeholder="Email" value={formData.email} onChange={handleChange} required />
          <input type="password" name="password" placeholder="Password" value={formData.password} onChange={handleChange} required />
          <button type="submit">Login</button>
        </form>
        <p>New to the library? <span onClick={() => navigate("/signup")} className="signup-link">Sign up</span></p>
      </div>
    </div>
  );
};

export default Login;
